from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    if not search_results:
        return {}

    # Initialize aggregation structure
    aggregated_data = defaultdict(lambda: {
        'scores': [],
        'custom_fields': defaultdict(list)
    })

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing group field values
        if group_value is None or group_value == "":
            group_value = 'unknown'

        # Accumulate data for default statistics
        aggregated_data[group_value]['scores'].append(result.score)

        # Accumulate data for custom aggregation functions
        if aggregation_funcs:
            for field_name, _ in aggregation_funcs.items():
                field_value = result.metadata.get(field_name)
                aggregated_data[group_value]['custom_fields'][field_name].append(field_value)

    # Compute aggregated statistics for each group
    aggregated_results = {}
    for group_value, data in aggregated_data.items():
        # Default statistics
        stats = {}
        scores = data['scores']
        count = len(scores)

        if count > 0:
            stats['count'] = count
            stats['avg_score'] = sum(scores) / count
            stats['max_score'] = max(scores)
            stats['min_score'] = min(scores)
        else:
            stats['count'] = 0
            stats['avg_score'] = 0.0
            stats['max_score'] = 0.0
            stats['min_score'] = 0.0

        # Custom aggregation functions
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                field_values = data['custom_fields'][field_name]
                # Filter out None/empty values before aggregation
                filtered_values = [v for v in field_values if v is not None and v != ""]
                if filtered_values:
                    try:
                        stats[field_name] = func(filtered_values)
                    except Exception as e:
                        # Handle potential errors in custom functions
                        stats[field_name] = f"Error: {str(e)}"
                else:
                    stats[field_name] = None

        aggregated_results[group_value] = stats

    return aggregated_results

